import streamlit as st
import requests
import json
import os
from dotenv import load_dotenv

load_dotenv()

st.set_page_config(page_title="PromptForge AI · ITJOLI", page_icon="⚡", layout="centered")

# Lee desde Streamlit Cloud secrets o desde .env local
GROQ_API_KEY = st.secrets.get("GROQ_API_KEY", os.getenv("GROQ_API_KEY"))

def call_ai(prompt: str) -> str:
    response = requests.post(
        "https://api.groq.com/openai/v1/chat/completions",
        headers={"Authorization": f"Bearer {GROQ_API_KEY}", "Content-Type": "application/json"},
        json={"model": "llama-3.3-70b-versatile", "messages": [{"role": "user", "content": prompt}], "max_tokens": 1000, "temperature": 0.1, "seed": 42}
    )
    response.raise_for_status()
    return response.json()["choices"][0]["message"]["content"].strip()

def init_state():
    defaults = {"step": 0, "profession": "", "exercise": "", "level": 1,
                "scores": [], "history": [], "done": 0, "feedback": None,
                "rewrite": None, "show_rewrite": False, "language": "Español"}
    for k, v in defaults.items():
        if k not in st.session_state:
            st.session_state[k] = v

init_state()

